<script lang="ts">import {formatMetric} from '$lib/core/scoring';let {data}=$props();let s=$derived(data.summary);</script>
<div class="hero"><div><h1>{s.firstName} {s.lastName}</h1><div class="muted">{s.kind==='core'?'Core player':'Substitute'} · chronological source history</div></div></div><div class="grid"><div class="card metric">Declared training<strong>{formatMetric(s.metrics.training)}</strong></div><div class="card metric">Official appearances<strong>{formatMetric(s.metrics.appearances)}</strong></div><div class="card metric">Match availability<strong>{formatMetric(s.metrics.availability)}</strong></div><div class="card metric">Overall administration<strong>{formatMetric(s.metrics.overallAdmin)}</strong></div></div><div class="card">{#each s.insights as i}<span class="pill">{i.label} · {i.detail}</span>{/each}{#if !s.insights.length}<span class="muted">No threshold-based observations.</span>{/if}</div><h2>Event history</h2><div class="history">{#each data.history as e}<div class="row"><span>{new Date(`${e.date}T12:00`).toLocaleDateString('en-BE')}</span><span class="pill">{e.type}</span><div><strong>{e.name}</strong><br/><small>{e.side??''} {e.opponent??''} {e.location??''}</small></div><div>Twizzit: <strong class={e.attendance??'unknown'}>{e.twizzitScorable?(e.attendance??'unknown'):'missing / failed'}</strong>{#if e.comment}<br/><small>Comment: {e.comment}</small>{/if}</div><div>Sportlink: {e.type==='match'?(e.sportlinkScorable?(e.appeared?'officially played':'not recorded as played'):'missing'):'n/a'}</div></div>{/each}</div>
